  1→import * as core from "@actions/core";
  2→import * as github from "@actions/github";
  3→import type { RadarConfig } from "../config";
  4→import type { ClassifiedCandidate } from "../sources/types";
  5→import { withRetry } from "../utils/retry";
  6→
  7→function escapeTableCell(value: string): string {
  8→  return value.replace(/\|/g, "\\|").replace(/\n/g, " ");
  9→}
 10→
 11→function buildIssueTitle(candidate: ClassifiedCandidate, config: RadarConfig): string {
 12→  const prefix = config.issue_template.title_prefix;
 13→  return `${prefix} ${escapeTableCell(candidate.title).slice(0, 200)}`;
 14→}
 15→
 16→function renderTemplate(template: string, candidate: ClassifiedCandidate): string {
 17→  return template
 18→    .replace(/\{\{name\}\}/g, candidate.title)
 19→    .replace(/\{\{url\}\}/g, candidate.url)
 20→    .replace(/\{\{description\}\}/g, candidate.description.slice(0, 100))
 21→    .replace(/\{\{language\}\}/g, candidate.metadata.language ?? "")
 22→    .replace(/\{\{stars\}\}/g, String(candidate.metadata.stars ?? ""))
 23→    .replace(/\{\{license\}\}/g, String((candidate.metadata as Record<string, unknown>).license ?? ""))
 24→    .replace(/\{\{source\}\}/g, candidate.source)
 25→    .replace(/\{\{category\}\}/g, candidate.suggestedCategory);
 26→}
 27→
 28→function buildIssueBody(candidate: ClassifiedCandidate, config: RadarConfig): string {
 29→  const lines = [
 30→    `## Candidate Resource`,
 31→    ``,
 32→    `| Field | Value |`,
 33→    `|-------|-------|`,
 34→  ];
 35→
 36→  const allFields: Record<string, () => string | null> = {
 37→    url: () => `| **URL** | ${escapeTableCell(candidate.url)} |`,
 38→    source: () => `| **Source** | ${escapeTableCell(candidate.source)} |`,
 39→    relevanceScore: () => `| **Relevance Score** | ${candidate.relevanceScore}/100 |`,
 40→    suggestedCategory: () => `| **Suggested Category** | ${escapeTableCell(candidate.suggestedCategory)} |`,
 41→    tags: () => candidate.suggestedTags.length > 0 ? `| **Tags** | ${candidate.suggestedTags.map((t) => `\`${escapeTableCell(t)}\``).join(", ")} |` : null,
 42→    stars: () => candidate.metadata.stars !== undefined ? `| **Stars** | ${candidate.metadata.stars} |` : null,
 43→    language: () => candidate.metadata.language ? `| **Language** | ${escapeTableCell(candidate.metadata.language)} |` : null,
 44→    authors: () => candidate.metadata.authors?.length ? `| **Authors** | ${escapeTableCell(candidate.metadata.authors.join(", "))} |` : null,
 45→  };
 46→
 47→  const fieldsToShow = config.issue_template.include_fields ?? Object.keys(allFields);
 48→  for (const field of fieldsToShow) {
 49→    if (allFields[field]) {
 50→      const row = allFields[field]();
 51→      if (row) lines.push(row);
 52→    }
 53→  }
 54→
 55→  const suggestedEntry = config.issue_template.suggested_entry_format
 56→    ? renderTemplate(config.issue_template.suggested_entry_format, candidate)
 57→    : `- [${candidate.title}](${candidate.url}) - ${candidate.description.slice(0, 100)}`;
 58→
 59→  if (candidate.metadata.license) {
 60→    lines.push(
 61→      `| **License** | ${escapeTableCell(candidate.metadata.license)} |`
 62→    );
 63→  }
 64→
 65→  if (candidate.metadata.archived !== undefined) {
 66→    lines.push(
 67→      `| **Archived** | ${candidate.metadata.archived ? "Yes" : "No"} |`
 68→    );
 69→  }
 70→
 71→  if (candidate.metadata.fork !== undefined) {
 72→    lines.push(
 73→      `| **Fork** | ${candidate.metadata.fork ? "Yes" : "No"} |`
 74→    );
 75→  }
 76→
 77→  if (candidate.metadata.owner) {
 78→    lines.push(
 79→      `| **Owner** | ${escapeTableCell(candidate.metadata.owner)} |`
 80→    );
 81→  }
 82→
 83→  if (candidate.metadata.homepage) {
 84→    lines.push(
 85→      `| **Homepage** | ${escapeTableCell(candidate.metadata.homepage)} |`
 86→    );
 87→  }
 88→
 89→  if (candidate.metadata.lastPushedAt) {
 90→    lines.push(
 91→      `| **Last Pushed** | ${escapeTableCell(candidate.metadata.lastPushedAt)} |`
 92→    );
 93→  }
 94→
 95→  lines.push(
 96→    ``,
 97→    `## Description`,
 98→    ``,
 99→    "```",
100→    (candidate.description || "No description available").slice(0, 1000),
101→    "```",
102→    ``,
103→    `## LLM Reasoning`,
104→    ``,
105→    "```",
106→    (candidate.reasoning || "No reasoning provided").slice(0, 500),
107→    "```",
108→    ``,
109→    `## Suggested Entry`,
110→    ``,
111→    `\`\`\`markdown`,
112→    suggestedEntry,
113→    `\`\`\``,
114→    ``,
115→    `---`,
116→    `*Generated by [awesome-list-radar](https://github.com/moven0831/awesome-list-radar)*`
117→  );
118→
119→  return lines.join("\n");
120→}
121→
122→export interface IssueClient {
123→  listIssues(labels: string[]): Promise<{ title: string; body?: string }[]>;
124→  createIssue(
125→    title: string,
126→    body: string,
127→    labels: string[]
128→  ): Promise<{ number: number; html_url: string }>;
129→}
130→
131→function makeGitHubClient(token: string): IssueClient {
132→  const octokit = github.getOctokit(token);
133→  const { owner, repo } = github.context.repo;
134→
135→  return {
136→    async listIssues(labels: string[]) {
137→      // Note: fetches up to 100 open issues. Repos with >100 open radar
138→      // issues may see duplicate issue creation. Use GitHub search API
139→      // for more robust dedup if this becomes an issue.
140→      const { data } = await octokit.rest.issues.listForRepo({
141→        owner,
142→        repo,
143→        state: "open",
144→        labels: labels.join(","),
145→        per_page: 100,
146→      });
147→      return data.map((i) => ({
148→        title: i.title,
149→        body: i.body ?? undefined,
150→      }));
151→    },
152→
153→    async createIssue(title: string, body: string, labels: string[]) {
154→      const { data } = await octokit.rest.issues.create({
155→        owner,
156→        repo,
157→        title,
158→        body,
159→        labels,
160→      });
161→      return { number: data.number, html_url: data.html_url };
162→    },
163→  };
164→}
165→
166→export async function createIssues(
167→  candidates: ClassifiedCandidate[],
168→  config: RadarConfig,
169→  dryRun: boolean,
170→  client?: IssueClient
171→): Promise<number> {
172→  if (candidates.length === 0) return 0;
173→
174→  const labels = config.issue_template.labels;
175→  const issueClient =
176→    client ?? makeGitHubClient(core.getInput("github_token"));
177→
178→  // Fetch existing issues for idempotency check
179→  let existingIssues: { title: string; body?: string }[] = [];
180→  try {
181→    existingIssues = await withRetry(() => issueClient.listIssues(labels));
182→  } catch (error) {
183→    core.warning(
184→      `Could not fetch existing issues: ${error instanceof Error ? error.message : String(error)}`
185→    );
186→  }
187→
188→  const existingUrls = new Set(
189→    existingIssues
190→      .map((issue) => {
191→        const match = issue.body?.match(
192→          /\| \*\*URL\*\* \| (https?:\/\/[^\s|]+)/
193→        );
194→        return match?.[1]?.toLowerCase();
195→      })
196→      .filter(Boolean)
197→  );
198→
199→  let created = 0;
200→
201→  for (const candidate of candidates) {
202→    if (existingUrls.has(candidate.url.toLowerCase())) {
203→      core.info(
204→        `Skipping "${candidate.title}" — issue already exists for ${candidate.url}`
205→      );
206→      continue;
207→    }
208→
209→    const title = buildIssueTitle(candidate, config);
210→    const body = buildIssueBody(candidate, config);
211→
212→    if (dryRun) {
213→      core.info(`[DRY RUN] Would create issue: ${title}`);
214→      core.info(`  URL: ${candidate.url}`);
215→      core.info(`  Score: ${candidate.relevanceScore}`);
216→      created++;
217→      continue;
218→    }
219→
220→    try {
221→      const issue = await withRetry(() =>
222→        issueClient.createIssue(title, body, labels)
223→      );
224→      core.info(`Created issue #${issue.number}: ${issue.html_url}`);
225→      created++;
226→    } catch (error) {
227→      core.warning(
228→        `Failed to create issue for "${candidate.title}": ${error instanceof Error ? error.message : String(error)}`
229→      );
230→    }
231→  }
232→
233→  return created;
234→}
235→
236→export { buildIssueTitle, buildIssueBody, escapeTableCell, renderTemplate };
