 1→import { readFileSync } from "node:fs";
 2→import * as core from "@actions/core";
 3→import type { RadarConfig } from "../config";
 4→import type { Candidate } from "../sources/types";
 5→
 6→const URL_REGEX = /https?:\/\/[^\s\)>\]]+/g;
 7→
 8→export function normalizeUrl(url: string): string {
 9→  let normalized = url.toLowerCase();
10→  // Remove protocol
11→  normalized = normalized.replace(/^https?:\/\//, "");
12→  // Remove www.
13→  normalized = normalized.replace(/^www\./, "");
14→  // Remove trailing slash
15→  normalized = normalized.replace(/\/+$/, "");
16→  // Remove tracking params
17→  try {
18→    const parsed = new URL("https://" + normalized);
19→    const paramsToRemove = [...parsed.searchParams.keys()].filter(
20→      (k) => k.startsWith("utm_") || k === "ref" || k === "source"
21→    );
22→    paramsToRemove.forEach((k) => parsed.searchParams.delete(k));
23→    // Reconstruct without protocol
24→    normalized = parsed.hostname + parsed.pathname + parsed.search;
25→    normalized = normalized.replace(/\/+$/, "");
26→  } catch {
27→    // If URL parsing fails, just use the lowercase version
28→  }
29→  return normalized;
30→}
31→
32→export function extractUrlsFromMarkdown(markdown: string): Set<string> {
33→  const urls = new Set<string>();
34→  const matches = markdown.match(URL_REGEX);
35→  if (matches) {
36→    for (const url of matches) {
37→      // Remove trailing punctuation before normalizing
38→      const cleaned = url.replace(/[.,;:!?]+$/, "");
39→      urls.add(normalizeUrl(cleaned));
40→    }
41→  }
42→  return urls;
43→}
44→
45→type ReadFileFn = (path: string, encoding: BufferEncoding) => string;
46→
47→export function dedup(
48→  candidates: Candidate[],
49→  config: RadarConfig,
50→  readFileFn: ReadFileFn = readFileSync as ReadFileFn
51→): Candidate[] {
52→  let existingUrls: Set<string>;
53→
54→  try {
55→    const markdown = readFileFn(config.list_file, "utf-8");
56→    existingUrls = extractUrlsFromMarkdown(markdown);
57→  } catch {
58→    core.warning(
59→      `Could not read list file "${config.list_file}", skipping dedup`
60→    );
61→    return candidates;
62→  }
63→
64→  const filtered = candidates.filter(
65→    (c) => !existingUrls.has(normalizeUrl(c.url))
66→  );
67→
68→  core.info(
69→    `Dedup: ${candidates.length} → ${filtered.length} candidates (${existingUrls.size} existing URLs)`
70→  );
71→  return filtered;
72→}
