  1→import * as core from "@actions/core";
  2→
  3→export interface RetryOptions {
  4→  maxRetries?: number;
  5→  baseDelay?: number;
  6→  maxDelay?: number;
  7→  retryableStatuses?: number[];
  8→}
  9→
 10→interface RetryableError extends Error {
 11→  status?: number;
 12→  response?: {
 13→    status: number;
 14→    headers: {
 15→      get(name: string): string | null;
 16→    };
 17→  };
 18→}
 19→
 20→function getRetryDelay(
 21→  attempt: number,
 22→  options: Required<RetryOptions>
 23→): number {
 24→  const exponential = options.baseDelay * Math.pow(2, attempt);
 25→  const jitter = Math.random() * options.baseDelay;
 26→  return Math.min(exponential + jitter, options.maxDelay);
 27→}
 28→
 29→function getRateLimitDelay(error: RetryableError): number | null {
 30→  const headers = error.response?.headers;
 31→  if (!headers) return null;
 32→
 33→  const retryAfter = headers.get("retry-after");
 34→  if (retryAfter) {
 35→    const seconds = parseInt(retryAfter, 10);
 36→    if (!isNaN(seconds)) return seconds * 1000;
 37→    const date = new Date(retryAfter).getTime();
 38→    if (!isNaN(date)) return Math.max(0, date - Date.now());
 39→  }
 40→
 41→  const rateLimitReset = headers.get("x-ratelimit-reset");
 42→  if (rateLimitReset) {
 43→    const resetTime = parseInt(rateLimitReset, 10) * 1000;
 44→    return Math.max(0, resetTime - Date.now());
 45→  }
 46→
 47→  return null;
 48→}
 49→
 50→function isRetryable(error: unknown, retryableStatuses: number[]): boolean {
 51→  if (error instanceof Error) {
 52→    const retryable = error as RetryableError;
 53→    const status = retryable.status ?? retryable.response?.status;
 54→    if (status && retryableStatuses.includes(status)) return true;
 55→
 56→    if (
 57→      retryable.message.includes("ECONNRESET") ||
 58→      retryable.message.includes("ETIMEDOUT") ||
 59→      retryable.message.includes("ENOTFOUND") ||
 60→      retryable.message.includes("fetch failed")
 61→    ) {
 62→      return true;
 63→    }
 64→  }
 65→  return false;
 66→}
 67→
 68→export async function withRetry<T>(
 69→  fn: () => Promise<T>,
 70→  options?: RetryOptions
 71→): Promise<T> {
 72→  const opts: Required<RetryOptions> = {
 73→    maxRetries: options?.maxRetries ?? 3,
 74→    baseDelay: options?.baseDelay ?? 1000,
 75→    maxDelay: options?.maxDelay ?? 30000,
 76→    retryableStatuses: options?.retryableStatuses ?? [
 77→      408, 429, 500, 502, 503, 504,
 78→    ],
 79→  };
 80→
 81→  for (let attempt = 0; attempt <= opts.maxRetries; attempt++) {
 82→    try {
 83→      return await fn();
 84→    } catch (error) {
 85→      if (
 86→        attempt === opts.maxRetries ||
 87→        !isRetryable(error, opts.retryableStatuses)
 88→      ) {
 89→        throw error;
 90→      }
 91→
 92→      const rateLimitDelay = getRateLimitDelay(error as RetryableError);
 93→      const delay = Math.min(
 94→        rateLimitDelay ?? getRetryDelay(attempt, opts),
 95→        opts.maxDelay
 96→      );
 97→
 98→      core.info(
 99→        `Retry ${attempt + 1}/${opts.maxRetries} after ${Math.round(delay)}ms: ${error instanceof Error ? error.message : String(error)}`
100→      );
